class Book:
    def __init__(self, title, author):
        self.title = title
        self.author = author
        self.checked_out = False

    def checkout(self):
        if self.checked_out:
            print(self.title, "is already checked out!")
        else:
            self.checked_out = True
            print("You checked out:", self.title)

    def return_book(self):
        self.checked_out = False
        print("Thanks for returning", self.title)


library = [
    Book("Charlotte's Web", "E.B. White"),
    Book("Matilda", "Roald Dahl"),
    Book("Holes", "Louis Sachar")
]

def find_book(title):
    for book in library:
        if book.title == title:
            return book
    return None

try:
    chosen = "Matilda"
    book = find_book(chosen)
    if book is None:
        raise ValueError("That book isn't in the library!")
    book.checkout()
    book.checkout()   # try checking it out twice on purpose
except ValueError as e:
    print("Error:", e)
